import React, { useState, useEffect } from "react";
import styles from "./nav-bar.module.css";
import NavButton from "../nav-button";
import MegaMenu, { SubItem } from "../mega-menu"; // Import SubItem type
import dataList from "../../nav-list/nav-list.json"; // Import the JSON data

const NavBar: React.FC = () => {
  const [activeDropdown, setActiveDropdown] = useState<string>("");
  const [discoveryDropdownData, setDiscoveryDropdownData] = useState<SubItem[]>(
    []
  );
  const [aboutDropdownData, setAboutDropdownData] = useState<SubItem[]>([]);

  // Function to toggle the active dropdown
  const toggleDropDown = (dropdownName: string): void => {
    setActiveDropdown(activeDropdown === dropdownName ? "" : dropdownName);
  };

  useEffect(() => {
    // Extract data for Discovery and About dropdowns from imported JSON data
    const discoveryData = dataList.find((item) => item.title === "Discovery");
    const aboutData = dataList.find((item) => item.title === "About");

    setDiscoveryDropdownData(discoveryData?.items || []);
    setAboutDropdownData(aboutData?.items || []);
  }, []);

  return (
    <>
      <div className={styles.nav__bar}>
        <NavButton
          text="Discovery"
          handleClick={() => toggleDropDown("Discovery")}
        />
        <NavButton text="About" handleClick={() => toggleDropDown("About")} />
        <NavButton text="Contact us" href="/contact" isLink={true} />
      </div>

      {activeDropdown === "Discovery" && (
        <MegaMenu dropDownObject={[{ subItems: discoveryDropdownData }]} show={true} />
      )}
      {activeDropdown === "About" && (
        <MegaMenu dropDownObject={[{ subItems: aboutDropdownData }]} show={true} />
      )}
    </>
  );
};

export default NavBar;


